code = """import json

# Load MongoDB documents from file
mongo_file = var_functions.query_db:26
with open(mongo_file, 'r') as f:
    civic_docs = json.load(f)

print('Loaded', len(civic_docs), 'civic documents')

# Extract project statuses
project_statuses = {}

for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    
    current_section = None
    
    for i, line in enumerate(lines):
        line = line.strip()
        if not line:
            continue
        
        # Detect section headers
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'not_started'
        
        # Extract project names
        if current_section and len(line) > 10:
            # Skip markers
            if line.startswith('(') or line.startswith('•') or line.startswith('■'):
                continue
            if 'Updates:' in line or 'Schedule:' in line or 'Project Description:' in line or 'Page' in line:
                continue
                
            # Check if this is a project name by looking at next lines
            if i + 1 < len(lines):
                next_segment = '\n'.join(lines[i:i+3])
                if 'Updates:' in next_segment or 'Schedule:' in next_segment or 'Project Description:' in next_segment:
                    base_name = line.split('(')[0].strip()
                    # Map status
                    if current_section == 'construction':
                        status = 'completed'
                    else:
                        status = current_section
                    project_statuses[base_name] = status

print('Extracted', len(project_statuses), 'project statuses')

# Load funding data
funding_data = var_functions.query_db:42

# Combine data
results = []
for rec in funding_data:
    project_name = rec['Project_Name']
    base_name = project_name.split('(')[0].strip()
    
    # Find status
    status = 'unknown'
    if base_name in project_statuses:
        status = project_statuses[base_name]
    else:
        # Fuzzy match
        for key, val in project_statuses.items():
            if base_name.lower() in key.lower() or key.lower() in base_name.lower():
                status = val
                break
    
    results.append([
        project_name,
        rec['Funding_Source'],
        int(rec['Amount']),
        status
    ])

# Sort by project name
results.sort(key=lambda x: x[0])

# Create output
output = []
for project_name, funding_source, amount, status in results:
    output.append(f"Project: {project_name}")
    output.append(f"Funding Source: {funding_source}")
    output.append(f"Amount: ${amount:,}")
    output.append(f"Status: {status}")
    output.append("-" * 70)

final_text = "\n".join(output)

print('Generated', len(results), 'final results')

result = {
    'count': len(results),
    'output': final_text
}

print('__RESULT__:')
print(json.dumps(result))"""

